import 'package:flutter/material.dart';import 'package:smart_scanner/core/theme/app_theme.dart';import 'package:smart_scanner/core/utils/app_date_formatter.dart';import 'package:smart_scanner/features/file_list/domain/entities/scan_file_entry.dart';class ScanFileListTile extends StatelessWidget {  const ScanFileListTile({    super.key,    required this.entry,    required this.onView,    required this.onDelete,    required this.onSend,    this.isDeleting = false,    this.isSending = false,  });  final ScanFileEntry entry;  final VoidCallback onView;  final VoidCallback onDelete;  final VoidCallback onSend;  final bool isDeleting;  final bool isSending;  static ButtonStyle _actionStyle({    required Color background,    required Color foreground,  }) {    return FilledButton.styleFrom(      backgroundColor: background,      foregroundColor: foreground,      disabledBackgroundColor: background.withValues(alpha: 0.55),      disabledForegroundColor: foreground.withValues(alpha: 0.7),      minimumSize: const Size(0, 40),      padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 10),      shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10)),      textStyle: const TextStyle(fontWeight: FontWeight.w600, fontSize: 14),    );  }  @override  Widget build(BuildContext context) {    final viewSendStyle = _actionStyle(      background: AppTheme.fileListAppBar,      foreground: Colors.white,    );    final deleteStyle = _actionStyle(      background: AppTheme.fileListDelete,      foreground: Colors.white,    );    return Container(      padding: const EdgeInsets.all(16),      decoration: BoxDecoration(        color: AppTheme.fileListCard,        borderRadius: BorderRadius.circular(12),      ),      child: Column(        crossAxisAlignment: CrossAxisAlignment.stretch,        children: [          const Text(            'Inspection List',            style: TextStyle(              color: Colors.white,              fontWeight: FontWeight.w700,              fontSize: 16,            ),          ),          const SizedBox(height: 6),          Text(            AppDateFormatter.fileListTile.format(entry.modifiedAt),            style: const TextStyle(              color: AppTheme.fileListSubtitle,              fontSize: 13,            ),          ),          const SizedBox(height: 14),          Row(            children: [              Expanded(                child: FilledButton(                  onPressed: onView,                  style: viewSendStyle,                  child: const Text('View'),                ),              ),              const SizedBox(width: 8),              Expanded(                child: FilledButton(                  onPressed: isDeleting ? null : onDelete,                  style: deleteStyle,                  child: isDeleting                      ? const SizedBox(                          width: 18,                          height: 18,                          child: CircularProgressIndicator(                            strokeWidth: 2,                            color: Colors.white,                          ),                        )                      : const Text('Delete'),                ),              ),              const SizedBox(width: 8),              Expanded(                child: FilledButton(                  onPressed: isSending ? null : onSend,                  style: viewSendStyle,                  child: isSending                      ? const SizedBox(                          width: 18,                          height: 18,                          child: CircularProgressIndicator(                            strokeWidth: 2,                            color: Colors.white,                          ),                        )                      : const Text('Send'),                ),              ),            ],          ),        ],      ),    );  }}